def is_vowel(*args, **kwargs):
    """
    Determine if a given character is a vowel. This function is essential for identifying vowels in the song title, which is a key step in calculating the prettiness of the song. The function checks if th
    """
    vowels = {'I', 'E', 'A', 'O', 'U', 'Y'}
    if args and len(args) > 0:
        c = args[0]
        return 1 if c.upper() in vowels else 0
    return 0
